// ─────────────────────────────────────────────────────────────
// MOCK: Etsy Receipt
// ─────────────────────────────────────────────────────────────
// This node is a placeholder until the Etsy developer app is approved.
// Replace the entire contents of this node with the real implementation below.
//
// REAL IMPLEMENTATION (3 steps to replace this node):
//
// STEP 1 — Fetch stored refresh token from Supabase:
//   GET envs table, key = 'etsy_refresh_token'
//
// STEP 2 — Exchange refresh token for access token:
//   POST https://api.etsy.com/v3/public/oauth/token
//   Body: { grant_type: 'refresh_token', client_id: '<your_keystring>', refresh_token: '<from_envs>' }
//   → Save new refresh_token back to envs table (resets 90-day expiry)
//   → Use access_token for step 3
//
// STEP 3 — Fetch full receipt:
//   GET resource_url (from webhook payload)
//   Header: Authorization: Bearer <access_token>
//   → Returns full receipt with buyer_email, transactions[].listing_id, receipt_id
// ─────────────────────────────────────────────────────────────

// Etsy webhook payload (real shape when live)
const payload = $input.first().json.body || $input.first().json;

// MOCK receipt — replace with real Etsy API response when app is approved
const receipt = {
  receipt_id: 'MOCK-RECEIPT-001',
  buyer_email: 'test@example.com',
  buyer_name: 'Test Buyer',
  transactions: [
    {
      listing_id: 'LISTING_ID_HERE', // ← replace with your real Etsy listing ID
      title: 'Personalized Space Hero Mission Storybook'
    }
  ]
};

return [{ json: { receipt, resource_url: payload.resource_url || 'MOCK' } }];

// ─────────────────────────────────────────────────────────────
// Map Etsy listing ID → theme
// Fill in your real listing IDs after the Etsy shop is live.
// You can find listing IDs in Etsy Shop Manager → Listings (in the URL).
// ─────────────────────────────────────────────────────────────

const LISTING_MAP = {
  'LISTING_ID_SPACE':    { theme: 'SPACE_HERO',          theme_label: 'Space Hero Mission' },
  'LISTING_ID_FANTASY':  { theme: 'FANTASY_HERO',        theme_label: 'Fantasy Hero Quest' },
  'LISTING_ID_PRINCESS': { theme: 'ENCHANTED_PRINCESS',  theme_label: 'Enchanted Princess Adventure' },
  'LISTING_ID_ANIMAL':   { theme: 'ANIMAL_GUARDIAN',     theme_label: 'Animal Guardian Hero' },
  'LISTING_ID_HOME':     { theme: 'HOME_HELPER',         theme_label: 'Home Helper Hero' },
};

const receipt = $input.first().json.receipt;
const listingId = String(receipt.transactions?.[0]?.listing_id || '');
const mapping = LISTING_MAP[listingId] || { theme: 'SPACE_HERO', theme_label: 'Space Hero Mission' };

return [{
  json: {
    receipt_id:    receipt.receipt_id,
    buyer_email:   receipt.buyer_email,
    buyer_name:    receipt.buyer_name,
    theme:         mapping.theme,
    theme_label:   mapping.theme_label,
    package_label: 'Basic (Storybook + Coloring + Certificate)',
  }
}];

// Generate a fresh intake token: EVRM-XXXXXXXX
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
let token = 'EVRM-';
for (let i = 0; i < 8; i++) {
  token += chars[Math.floor(Math.random() * chars.length)];
}

const data = $input.first().json;

return [{
  json: {
    ...data,
    intake_token: token,
  }
}];
